INSERT INTO "assistant_faqs" ("question", "answer", "category", "usage_count") VALUES
('Como compro productos en PorKCasare?', 'Para comprar productos, ve a la pestana "Consumo" en tu oficina virtual. Alli veras el catalogo con todas las categorias (carnes, bebidas, alimentos, aseo, etc.). Selecciona los productos que desees, agregalos al carrito con el boton del carrito y procede al checkout. Puedes pagar con Nequi, Daviplata o MercadoPago. Si pagas por Nequi/Daviplata, envia el comprobante por WhatsApp al +573125929316.', 'compras', 50),
('Cuanto cuesta el paquete inicial?', 'El Paquete Inicial es de 15kg y cuesta $300.000 COP para distribuidores o $375.000 COP para clientes. Equivale a 50 puntos, que es el minimo necesario para activar tu codigo y empezar a recibir comisiones y bonos.', 'compras', 45),
('Como subo mis documentos?', 'En tu oficina virtual, busca la seccion "Documentos". Debes subir 4 archivos: cedula frontal, cedula posterior, RUT y certificacion bancaria. Los formatos aceptados son PDF, JPG y PNG, con un maximo de 5MB por archivo. Una vez subidos los 4 documentos, tu estado cambia a "pendiente de validacion" y un administrador los revisara.', 'documentos', 40),
('Como funcionan las comisiones?', 'Las comisiones funcionan en 5 niveles. Cuando alguien de tu red compra, cada uno de los 5 niveles superiores recibe el 10% del valor del pedido. Ejemplo: un pedido de 50 puntos ($140.000 COP) genera $14.000 COP para cada nivel. Ademas, en la primera compra de 50+ puntos de un referido, el patrocinador directo recibe un Bono Quick Start de 21 puntos. Para cobrar comisiones necesitas estar activo (10+ puntos personales al mes).', 'comisiones', 40),
('Como funciona mi red de referidos?', 'Tu red funciona con un sistema unilevel: puedes referir a personas ilimitadas (tu frontline). Las comisiones suben hasta 5 niveles. Para ver y gestionar tu red, ve a la pestana "Duplicacion" en tu oficina virtual. Alli encontraras tu arbol de red, link de referido para compartir, y podras ver quienes estan activos (verde) o inactivos (gris).', 'red', 35),
('Como comparto mi link de referido?', 'Tu link de referido lo encuentras en la pestana "Duplicacion" de tu oficina virtual. Hay un boton para copiarlo al portapapeles. Cuando alguien se registra usando tu link, tu nombre aparece automaticamente como su patrocinador.', 'red', 30),
('Cuales son los rangos y como avanzo?', 'Los rangos son: Plata ($1.4M, 500 pts), Oro ($4.2M, 1.500 pts), Estrellas ($8.4M, 3.000 pts), Diamante ($14M, 5.000 pts) y Corona ($28M, 10.000 pts). Se alcanzan acumulando comisiones y puntos personales. Desde el rango Plata puedes subir tu foto de perfil personalizada.', 'rangos', 25),
('Como retiro mis comisiones?', 'Para retirar comisiones necesitas un minimo de $20.000 COP en tu wallet. Solo pueden retirar los Masters o distribuidores con 50+ puntos personales. Los pagos se programan para el 15 o el 30 de cada mes. Ve a la seccion de tu wallet en la oficina virtual para solicitar un retiro.', 'comisiones', 25),
('Que necesito para activar mi codigo?', 'Para activar tu codigo y empezar a recibir bonos y comisiones, necesitas hacer una compra minima de 50 puntos (equivalente al Paquete Inicial de 15kg por $300.000 COP para distribuidores). Sin esta compra inicial, no podras acceder al sistema de comisiones.', 'registro', 20),
('Que inversiones hay disponibles?', 'Actualmente hay 4 opciones de inversion en la seccion "Inversiones" de la pestana Consumo: KPC Capital (activa, enfocada en capital digital), Ganaderia Futura (proximamente, ciclos ganaderos), Siembra KPC (proximamente, produccion agricola) y Agro Expansion (en revision, expansion agricola). Solo KPC Capital esta activa actualmente.', 'inversiones', 20),
('Como funcionan los juegos?', 'En la pestana "Consumo" seccion "Retos" hay 4 juegos: Juego de Memoria (encuentra parejas, recompensa $60.000/10 pts), Trivia PorKCasare (preguntas sobre productos), Rompecabezas (arma imagenes por niveles) y Rueda de la Fortuna (gira para ganar). Todos tienen limites mensuales y sistema de vidas para evitar abuso.', 'juegos', 15),
('Cuanto cuesta el envio?', 'El costo de envio depende de tu ubicacion y la cantidad de Unidades de Envio (UE). En Yopal: 1-5 UE = $5.000, 6-10 UE = $8.000, 11+ UE = $12.000. Otras ciudades: 1-3 UE = $16.000, 4-6 UE = $22.000, 7-10 UE = $30.000, 11-15 UE = $40.000, 16+ UE = $50.000. La recogida en punto es gratis.', 'compras', 15),
('Como me registro en PorKCasare?', 'Para registrarte necesitas ingresar: usuario, contrasena, nombre, apellido, numero de documento, email, celular y direccion. Si alguien te refirio, usa su link de referido y su nombre aparecera automaticamente como tu patrocinador. Despues del registro, haz una compra minima de 50 puntos para activar tu codigo.', 'registro', 15),
('Que significan los puntos personales y grupales?', 'Los puntos personales se ganan con tus propias compras (ej: 10 puntos por paquete de 3kg). Necesitas minimo 10 al mes para estar activo y recibir comisiones. Los puntos grupales se ganan de las compras de tu red (downline) como comisiones. 1 punto equivale a $2.800 COP.', 'puntos', 15),
('Como contacto a soporte?', 'Puedes contactar al equipo de soporte por WhatsApp al +573125929316. Tambien sirve para enviar comprobantes de pago y resolver cualquier duda que el asistente no pueda resolver.', 'soporte', 10),
('Que metodos de pago aceptan?', 'Aceptamos Nequi, Daviplata y MercadoPago. Para pagos por Nequi o Daviplata, debes enviar el comprobante de pago por WhatsApp al +573125929316 para que se confirme tu pedido. MercadoPago permite pago directo en linea.', 'compras', 10),
('Que pasa si no estoy activo en un mes?', 'Si no acumulas al menos 10 puntos personales en un mes, tu estado sera "inactivo" y perderas todas las comisiones generadas por tu red durante ese mes. Las comisiones no se recuperan. Para mantenerte activo, asegurate de comprar al menos un paquete de 3kg ($60.000 COP / 10 puntos) cada mes.', 'comisiones', 10),
('Donde encuentro el material educativo?', 'El material educativo esta en la pestana "Educacion" de tu oficina virtual. Alli encontraras: videos educativos sobre la plataforma y productos, libros y documentos de formacion, el PEC del Mes (Paquete de Educacion Continua) y enlaces utiles para distribuidores.', 'educacion', 10),
('Que es el Bono Quick Start?', 'El Bono Quick Start se activa cuando un referido hace su primera compra de 50 o mas puntos. El patrocinador directo recibe 21 puntos por cada paquete de 50 puntos comprado, y los 4 niveles superiores reciben 1 punto cada uno. Solo aplica en la primera compra del referido.', 'comisiones', 10),
('Cuales son las categorias de productos?', 'Las categorias principales son: Carnes (chuletas, costillitas, paticas, panceta, pulpa, goulast en paquetes de 3kg), Bebidas, Alimentos, Aseo, Higiene, Abarrotes y PEC. El precio distribuidor de un paquete de 3kg es $60.000 COP (10 puntos) y el precio cliente es $75.000 COP.', 'compras', 10);
